import org.springframework.web.client.HttpServerErrorException;
import org.springframework.web.client.ResourceAccessException;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import java.net.URI;
import java.net.URISyntaxException;

/**
 * Service for fetching web page content from URLs.
 */
@Service
public class WebPageFetcherService {

    private final RestTemplate restTemplate;

    /**
     * Constructor with dependency injection for RestTemplate.
     * @param restTemplate RestTemplate instance
     */
    @Autowired
    public WebPageFetcherService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    /**
     * Fetches the HTML content of a webpage from the given URL.
     * 
     * @param url The URL of the webpage to fetch
     * @return The HTML source code as a string
     * @throws IllegalArgumentException if the URL is null, empty, or invalid
     * @throws WebPageFetchException if there's an error fetching the webpage content
     */
    public String getPageContent(String url) {
        // Validate input
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        try {
            // Validate URL format
            URI uri = new URI(url);
            if (!uri.isAbsolute()) {
                throw new IllegalArgumentException("URL must be absolute: " + url);
            }

            // Set headers to mimic a standard browser request
            HttpHeaders headers = new HttpHeaders();
            headers.set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36");
            headers.set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8");
            headers.set("Accept-Language", "en-US,en;q=0.9");
            // Remove Accept-Encoding header to prevent automatic decompression issues
            headers.set("Connection", "keep-alive");

            HttpEntity<String> entity = new HttpEntity<>(headers);

            // Make the HTTP GET request
            ResponseEntity<String> response = restTemplate.exchange(
                uri, 
                HttpMethod.GET, 
                entity, 
                String.class
            );

            // Check response status
            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                return response.getBody();
            } else {
                throw new WebPageFetchException("Failed to fetch webpage. HTTP Status: " + 
                    response.getStatusCode() + ", URL: " + url);
            }

        } catch (URISyntaxException e) {
            throw new IllegalArgumentException("Invalid URL format: " + url, e);
        } catch (HttpClientErrorException e) {
            throw new WebPageFetchException("Client error when fetching webpage: " + 
                e.getStatusCode() + ", URL: " + url, e);
        } catch (HttpServerErrorException e) {
            throw new WebPageFetchException("Server error when fetching webpage: " + 
                e.getStatusCode() + ", URL: " + url, e);
        } catch (ResourceAccessException e) {
            throw new WebPageFetchException("Network error when fetching webpage. URL: " + url, e);
        } catch (RestClientException e) {
            throw new WebPageFetchException("Error fetching webpage content. URL: " + url, e);
        }
    }

    /**
     * Custom exception for web page fetching errors.
     */
    public static class WebPageFetchException extends RuntimeException {
        public WebPageFetchException(String message) {
            super(message);
        }

        public WebPageFetchException(String message, Throwable cause) {
            super(message, cause);
        }
    }
